// ─── KONFIGURATION ───────────────────────────────────
// Hier eure Werbekonten eintragen (act_ID Format)
const AD_ACCOUNTS = [
  'act_111111111111',
  'act_222222222222',
  'act_333333333333',
  // ... weitere Konten
];

// Mapping: Account-ID → Kundenname (für Google Drive Ordner)
const ACCOUNT_NAMES = {
  'act_111111111111': 'Kunde_A_GmbH',
  'act_222222222222': 'Kunde_B_AG',
  'act_333333333333': 'Kunde_C_UG',
};

// Zeitraum: Vormonat
const now = new Date();
const firstOfLastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const lastOfLastMonth = new Date(now.getFullYear(), now.getMonth(), 0);

const dateFrom = firstOfLastMonth.toISOString().split('T')[0];
const dateTo = lastOfLastMonth.toISOString().split('T')[0];

return [{
  json: {
    accounts: AD_ACCOUNTS,
    accountNames: ACCOUNT_NAMES,
    dateFrom,
    dateTo,
    scraperInput: JSON.stringify({
      accounts: AD_ACCOUNTS,
      dateFrom,
      dateTo,
    }),
  }
}];

// Scraper-Output parsen
const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';

// JSON-Ergebnis aus dem Output extrahieren
const jsonMatch = stdout.match(/--- RESULT_JSON ---\n([\s\S]*?)\n--- END_RESULT ---/);

if (!jsonMatch) {
  // Fehler oder Session abgelaufen
  if (stdout.includes('SESSION_EXPIRED') || stderr.includes('SESSION_EXPIRED')) {
    throw new Error('Meta Session abgelaufen! Bitte login.js erneut auf dem Server ausführen.');
  }
  throw new Error(`Scraper-Fehler: ${stderr || stdout}`);
}

const result = JSON.parse(jsonMatch[1]);

if (!result.success || result.downloaded === 0) {
  // Keine Dateien → Warnung aber kein Abbruch
  return [{
    json: {
      warning: 'Keine Rechnungen gefunden',
      result,
      stderr: stderr.substring(0, 500),
    }
  }];
}

// Pro heruntergeladene Datei ein Item erstellen
const config = $('⚙️ Konfiguration').first().json;

return result.files.map(file => ({
  json: {
    filePath: file.file,
    fileName: file.filename,
    accountId: file.account,
    customerName: config.accountNames[file.account] || file.account,
    dateFrom: config.dateFrom,
    dateTo: config.dateTo,
  }
}));

// Google Drive Ordnerstruktur:
// /Meta Rechnungen/
//   /Kunde_A_GmbH/
//     /2025-01/
//   /Kunde_B_AG/
//     /2025-01/

// ANPASSEN: Die ID eures Basis-Ordners in Google Drive
const BASE_FOLDER_ID = 'HIER_EURE_GOOGLE_DRIVE_FOLDER_ID';

// Monatlicher Unterordner
const dateFrom = $json.dateFrom;
const monthFolder = dateFrom.substring(0, 7); // z.B. '2025-01'

// Ordnerpfad für diesen Kunden
const folderPath = `${$json.customerName}/${monthFolder}`;

return [{
  json: {
    ...$json,
    baseFolderId: BASE_FOLDER_ID,
    folderPath,
    driveFolderId: BASE_FOLDER_ID, // Wird ggf. durch Subfolder-Logik ersetzt
  }
}];

// HINWEIS: Für automatische Subfolder-Erstellung
// kann ein separater Google Drive Node vorgeschaltet werden,
// der prüft ob der Ordner existiert und ihn ggf. anlegt.

